import { useSelector } from "react-redux";
import { selectTasks } from "../../store/tasksSlice";
import { selectStatusFilter, StatusFilter } from "../../store/filtersSlice";
import TaskItem from "../TaskItem/TaskItem";
import styles from "./TaskList.module.css";

function getVisibleTasks(tasks, filter) {
  switch (filter) {
    case StatusFilter.Active:
      return tasks.filter((t) => !t.completed);
    case StatusFilter.Completed:
      return tasks.filter((t) => t.completed);
    default:
      return tasks;
  }
}

export default function TaskList() {
  const tasks = useSelector(selectTasks);
  const filter = useSelector(selectStatusFilter);
  const visibleTasks = getVisibleTasks(tasks, filter);

  if (tasks.length === 0) {
    return <p className={styles.empty}>No tasks yet. Add one above!</p>;
  }

  if (visibleTasks.length === 0) {
    return <p className={styles.empty}>No tasks match the current filter.</p>;
  }

  return (
    <ul className={styles.list}>
      {visibleTasks.map((task) => (
        <TaskItem key={task.id} {...task} />
      ))}
    </ul>
  );
}
